   162→        val = lookup[(unsigned char)*src++];
   163→        if(val == 0xff) /* bad symbol */
   164→          goto bad;
   165→        x = (x << 6) | val;
   166→      }
   167→    }
   168→    if(padding == 1)
   169→      pos[1] = (x >> 8) & 0xff;
   170→    pos[0] = (x >> 16) & 0xff;
   171→    pos += 3 - padding;
   172→  }
   173→
   174→  /* Zero terminate */
   175→  *pos = '\0';
   176→
   177→  /* Return the decoded data */
   178→  *outptr = newstr;
   179→  *outlen = rawlen;
   180→
   181→  return CURLE_OK;
   182→bad:
   183→  free(newstr);
   184→  return CURLE_BAD_CONTENT_ENCODING;
   185→}
