   187→static CURLcode base64_encode(const char *table64,
   188→                              const char *inputbuff, size_t insize,
   189→                              char **outptr, size_t *outlen)
   190→{
   191→  char *output;
   192→  char *base64data;
   193→  const unsigned char *in = (unsigned char *)inputbuff;
   194→  const char *padstr = &table64[64];    /* Point to padding string. */
   195→
   196→  *outptr = NULL;
   197→  *outlen = 0;
   198→
   199→  if(!insize)
   200→    insize = strlen(inputbuff);
   201→
   202→  base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   203→  if(!output)
   204→    return CURLE_OUT_OF_MEMORY;
   205→
   206→  while(insize >= 3) {
   207→    *output++ = table64[ in[0] >> 2 ];
   208→    *output++ = table64[ ((in[0] & 0x03) << 4) | (in[1] >> 4) ];
   209→    *output++ = table64[ ((in[1] & 0x0F) << 2) | ((in[2] & 0xC0) >> 6) ];
   210→    *output++ = table64[ in[2] & 0x3F ];
   211→    insize -= 3;
   212→    in += 3;
   213→  }
   214→  if(insize) {
   215→    /* this is only one or two bytes now */
   216→    *output++ = table64[ in[0] >> 2 ];
   217→    if(insize == 1) {
   218→      *output++ = table64[ ((in[0] & 0x03) << 4) ];
   219→      if(*padstr) {
   220→        *output++ = *padstr;
   221→        *output++ = *padstr;
   222→      }
   223→    }
   224→    else {
   225→      /* insize == 2 */
   226→      *output++ = table64[ ((in[0] & 0x03) << 4) | ((in[1] & 0xF0) >> 4) ];
   227→      *output++ = table64[ ((in[1] & 0x0F) << 2) ];
   228→      if(*padstr)
   229→        *output++ = *padstr;
   230→    }
   231→  }
   232→
   233→  /* Zero terminate */
   234→  *output = '\0';
   235→
   236→  /* Return the pointer to the new data (allocated memory) */
   237→  *outptr = base64data;
   238→
   239→  /* Return the length of the new data */
   240→  *outlen = output - base64data;
   241→
   242→  return CURLE_OK;
   243→}
